def entity_split(pairs, train_entities):
    train, test = [], []
    for p in pairs:
        ents = {p["a"], p["b"]}
        if ents & train_entities and not ents <= train_entities:
            # spill: un extremo en train y otro fuera → test o drop; aquí drop de train
